import PropTypes from 'prop-types';

function UserCard({ name, age, isAdmin, onClick }) {
  return (
    <div onClick={onClick}>
      <strong>{name}</strong>
      {isAdmin && <span> (admin)</span>}
      <span> — age {age}</span>
    </div>
  );
}

UserCard.propTypes = {
  name:    PropTypes.string.isRequired,
  age:     PropTypes.number,
  isAdmin: PropTypes.bool,
  onClick: PropTypes.func,
};

PostCard.propTypes = {
  post: PropTypes.shape({
    id:      PropTypes.number.isRequired,
    title:   PropTypes.string.isRequired,
    author:  PropTypes.string,
    tags:    PropTypes.arrayOf(PropTypes.string),
  }).isRequired,
};

// Warns if any undeclared key is passed (e.g. `post.slug`)
PostCard.propTypes = {
  post: PropTypes.exact({
    id:    PropTypes.number.isRequired,
    title: PropTypes.string.isRequired,
  }).isRequired,
};

TagList.propTypes = {
  tags: PropTypes.arrayOf(PropTypes.string).isRequired,
  // or with shape:
  users: PropTypes.arrayOf(
    PropTypes.shape({ id: PropTypes.number, name: PropTypes.string })
  ),
};

// { us: 1500, uk: 900, fr: 700 }
StatsTable.propTypes = {
  visitsByCountry: PropTypes.objectOf(PropTypes.number),
};

Countdown.propTypes = {
  // Accept either a number of seconds or a Date object
  deadline: PropTypes.oneOfType([
    PropTypes.number,
    PropTypes.instanceOf(Date),
  ]).isRequired,
};

function positiveNumber(props, propName, componentName) {
  const value = props[propName];
  if (value === undefined || value === null) return null; // optional — missing is ok
  if (typeof value !== 'number' || value <= 0) {
    return new Error(
      `Invalid prop \`${propName}\` supplied to \`${componentName}\`. ` +
      `Expected a positive number, got ${value}.`
    );
  }
  return null;
}

ProgressBar.propTypes = {
  percentage: positiveNumber,
};

import PropTypes from 'prop-types';

function Badge({ label = 'New', color = 'blue', count = 0 }) {
  return (
    <span className={`badge badge-${color}`}>
      {label}{count > 0 && ` (${count})`}
    </span>
  );
}

Badge.propTypes = {
  label: PropTypes.string,
  color: PropTypes.oneOf(['blue', 'green', 'red', 'yellow']),
  count: PropTypes.number,
};

import PropTypes from 'prop-types';

function ArticleCard({ article, onBookmark, compact = false }) {
  const { title, author, tags, publishedAt, readingTimeMin } = article;
  return (
    <article className={compact ? 'card card--compact' : 'card'}>
      <h2>{title}</h2>
      <p>
        By <strong>{author.name}</strong> on{' '}
        {new Date(publishedAt).toLocaleDateString()}
      </p>
      <p>{readingTimeMin} min read</p>
      <ul>
        {tags.map(tag => <li key={tag}>{tag}</li>)}
      </ul>
      {onBookmark && (
        <button onClick={() => onBookmark(article.id)}>Bookmark</button>
      )}
    </article>
  );
}

ArticleCard.propTypes = {
  article: PropTypes.shape({
    id:             PropTypes.number.isRequired,
    title:          PropTypes.string.isRequired,
    author:         PropTypes.shape({
      name:         PropTypes.string.isRequired,
      avatarUrl:    PropTypes.string,
    }).isRequired,
    tags:           PropTypes.arrayOf(PropTypes.string).isRequired,
    publishedAt:    PropTypes.string.isRequired,   // ISO date string
    readingTimeMin: PropTypes.number.isRequired,
  }).isRequired,
  onBookmark: PropTypes.func,
  compact:    PropTypes.bool,
};

import { render } from '@testing-library/react';
import UserCard from './UserCard';

test('warns when required name prop is missing', () => {
  const spy = jest.spyOn(console, 'error').mockImplementation(() => {});

  render(<UserCard />); // name is required but absent

  expect(spy).toHaveBeenCalledWith(
    expect.stringContaining('Failed prop type'),
    expect.stringContaining('name'),
    expect.stringContaining('UserCard'),
    expect.anything(),
    expect.anything(),
  );

  spy.mockRestore();
});

test('does not warn when all required props are provided', () => {
  const spy = jest.spyOn(console, 'error').mockImplementation(() => {});

  render(<UserCard name="Alice" />);

  expect(spy).not.toHaveBeenCalled();
  spy.mockRestore();
});

import PropTypes from 'prop-types';

// Accepts any renderable content as children
function Card({ children }) {
  return <div className="card">{children}</div>;
}
Card.propTypes = {
  children: PropTypes.node.isRequired,
};

// Must receive exactly one React element
function Tooltip({ children, text }) {
  return <span title={text}>{children}</span>;
}
Tooltip.propTypes = {
  children: PropTypes.element.isRequired,
  text:     PropTypes.string.isRequired,
};

// Accepts a component type (for as/render-as patterns)
function Icon({ as: Component = 'span', label }) {
  return <Component aria-label={label} />;
}
Icon.propTypes = {
  as:    PropTypes.elementType,
  label: PropTypes.string.isRequired,
};

