import PropTypes from 'prop-types';

export const userShape = PropTypes.shape({
  id:        PropTypes.number.isRequired,
  name:      PropTypes.string.isRequired,
  email:     PropTypes.string.isRequired,
  avatarUrl: PropTypes.string,
  role:      PropTypes.oneOf(['admin', 'editor', 'viewer']).isRequired,
});

// src/components/UserCard.jsx
import { userShape } from '../propTypes/user';
function UserCard({ user }) { /* … */ }
UserCard.propTypes = { user: userShape.isRequired };

// src/components/UserList.jsx
import { userShape } from '../propTypes/user';
function UserList({ users }) { /* … */ }
UserList.propTypes = { users: PropTypes.arrayOf(userShape).isRequired };

import { Component } from 'react';
import PropTypes from 'prop-types';

class ProfileCard extends Component {
  static propTypes = {
    username:     PropTypes.string.isRequired,
    bio:          PropTypes.string,
    followerCount: PropTypes.number,
  };

  render() {
    const { username, bio, followerCount = 0 } = this.props;
    return (
      <div>
        <h2>@{username}</h2>
        {bio && <p>{bio}</p>}
        <span>{followerCount} followers</span>
      </div>
    );
  }
}
